def _normalize_district(name):
    if not name:
        return name
    return _DISTRICT_ALIASES.get(name, name)

def _score_district(district, city):
    """Check district first (with alias normalization), then city name."""
    d = _normalize_district(district)
    if d and d in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[d])
    c = _normalize_district(city)
    if c and c in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[c])
    return float(_DEFAULT_DISTRICT_SCORE)


def _score_price(price):
    # Filter from 500k; ≤700k scores 10 (ideal), above — decreasing
    if price is None:
        return 5.0  # neutral, not redistributed
    if price <= 700_000:
        return 10.0
    if price <= 900_000:
        return 10.0 - 3.0 * (price - 700_000) / 200_000   # 700k→10, 900k→7
    if price <= 1_200_000:
        return max(0.0, 7.0 - 7.0 * (price - 900_000) / 300_000)  # 900k→7, 1200k→0
    return 0.0


def _score_area(area):
    if area is None:
        return 5.0
    if area < 70 or area > 120:
        return 0.0
    if 85 <= area <= 105:
        return 10.0
    if area < 85:
        return 4.0 + 6.0 * (area - 70) / 15   # 70→4, 85→10
    return 10.0 - 3.0 * (area - 105) / 15      # 105→10, 120→7


def _score_rooms(rooms):
    if rooms is None:
        return 5.0  # neutral, not redistributed
    if rooms == 4:
        return 10.0
    if rooms == 5:
        return 8.0
    if rooms in (3, 6):
        return 7.0
    return 3.0  # ≤2 or 7+


def _score_transport(tp, tram_min, dist_center_min):
    # ≤5 мин → 10; каждая доп. минута −1 балл; <0 → 0
    m = tram_min if tram_min is not None else dist_center_min
    if m is None:
        return 5.0
    return max(0.0, 10.0 - max(0, m - 5))


def _score_type(tp):
    return 9.0


_BASE_W = {
    "district":  0.30,
    "transport": 0.20,
    "price":     0.15,
    "area":      0.20,
    "rooms":     0.15,
    "type":      0.00,
}


def compute_score(price, area, rooms, tp, dist_tram, dist_center, tram_min=None, dist_center_min=None, district=None, city=None, lat=None, lon=None, noise=None, floor=None, supermarket=None, district_score=None):
    d_sc = district_score if district_score is not None else _score_district(district, city)
    factors = [
        (_score_transport(tp, tram_min, dist_center_min), _BASE_W["transport"]),
        (d_sc,                                           _BASE_W["district"]),
        (_score_price(price),                           _BASE_W["price"]),
        (_score_area(area),                             _BASE_W["area"]),
        (_score_rooms(rooms),                           _BASE_W["rooms"]),
        (_score_type(tp),                               _BASE_W["type"]),
    ]
    total_w = sum(w for _, w in factors)
    base = sum(sc * w for sc, w in factors) / total_w
    penalty = _nuisance_penalty(lat, lon) + _noise_penalty(noise, floor)
    super_bonus = _supermarket_bonus(supermarket)
    return round(max(0.0, base - penalty + super_bonus), 1)


_SUPER_DECAY = {"hyper": (0.3, 10.0), "super": (0.2, 5.0), "discount": (0.1, 2.0)}

def _supermarket_bonus(sup_entry):
    if not sup_entry:
        return 0.0
    best = 0.0
    for tier, (max_b, max_d) in _SUPER_DECAY.items():
        d = (sup_entry.get(tier) or {}).get("dist_km")
        if d is not None and d < max_d:
            best = max(best, max_b * (1 - d / max_d))
    return round(best, 2)


def _f(v):
    try:
        return float(v) if v not in (None, "") else None
    except (ValueError, TypeError):
        return None


def _rooms(raw):
    if raw in (None, ""):
        return None
    if str(raw) == "7+":
        return 7
    try:
        return int(raw)
    except (ValueError, TypeError):
        return None


def score_from_csv(r):
    return compute_score(
        price=_f(r.get("price_zl")),
        area=_f(r.get("area_m2")),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=_f(r.get("drive_tram_km")) or _f(r.get("dist_tram")),
        dist_center=_f(r.get("drive_ratusz_km")) or _f(r.get("dist_km")),
        district=r.get("district", ""),
        city=r.get("city", ""),
    )


def score_from_jsrow(r):
    return compute_score(
        price=r.get("price"),
        area=r.get("area"),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=r.get("dist_tram"),
        dist_center=r.get("dist"),
        tram_min=r.get("tram_min"),
        dist_center_min=r.get("dist_min"),
        district=r.get("district", ""),
        city=r.get("city", ""),
        lat=r.get("lat"),
        lon=r.get("lon"),
        noise=r.get("noise"),
        floor=r.get("floor"),
        supermarket=r.get("supermarket"),
        district_score=r.get("district_score"),
    )
